// Normalize input from either Telegram path or Execute Workflow path
let transcript, chatId, pageId, ideaReference, source;

// Try Execute Workflow Trigger first (Smart Focus / external call path)
try {
  const wfData = $('Execute Workflow Trigger').first().json;
  if (wfData && (wfData.pageId || wfData.idea_reference || wfData.transcript)) {
    transcript = wfData.transcript || '';
    chatId = wfData.chatId || '';
    pageId = wfData.pageId || null;
    ideaReference = wfData.idea_reference || '';
    source = 'execute_workflow';
  }
} catch(e) {}

// If no workflow data, use Telegram path (voice or text)
if (!source) {
  try {
    const voiceData = $('Edit Fields (Voice)').first().json;
    if (voiceData && voiceData.transcript) {
      transcript = voiceData.transcript;
      chatId = voiceData.chatId;
      source = voiceData.source;
    }
  } catch(e) {}

  if (!source) {
    try {
      const textData = $('Edit Fields (Text)').first().json;
      if (textData && textData.transcript) {
        transcript = textData.transcript;
        chatId = textData.chatId;
        source = textData.source;
      }
    } catch(e) {}
  }

  // Extract idea reference from transcript (e.g. "todos pour [nom idée]")
  ideaReference = '';
  if (transcript) {
    const match = transcript.match(/(?:todos?|tâches?|steps?)\s+(?:pour|de|of)\s+["']?([^"'\n]+?)["']?\s*$/i);
    ideaReference = match ? match[1].trim() : transcript;
  }
}

return [{ json: { transcript, chatId, pageId, idea_reference: ideaReference, source } }];

// Handle search results: 0, 1, or N results
const results = $input.all();
const inputData = $('Normalize Input').first().json;
const count = results.length;

if (count === 0) {
  return [{ json: { found: 'none', chatId: inputData.chatId } }];
} else if (count === 1) {
  return [{ json: { found: 'one', pageId: results[0].json.id, chatId: inputData.chatId } }];
} else {
  // Multiple results — pick best match or flag ambiguity
  const ref = (inputData.idea_reference || '').toLowerCase();
  const exactMatch = results.find(r => {
    const title = (r.json.property_title || r.json.name || '').toLowerCase();
    return title === ref;
  });
  if (exactMatch) {
    return [{ json: { found: 'one', pageId: exactMatch.json.id, chatId: inputData.chatId } }];
  }
  // Ambiguous
  const options = results.slice(0, 5).map(r => ({
    id: r.json.id,
    title: r.json.property_title || r.json.name || 'Sans titre'
  }));
  return [{ json: { found: 'many', options, chatId: inputData.chatId } }];
}

// Ambiguous results — format message
const data = $json;
const options = data.options || [];
let message = '⚠️ Plusieurs idées trouvées :\n\n';
options.forEach((opt, idx) => {
  message += `${idx + 1}. ${opt.title}\n`;
});
message += '\nPrécise le nom exact de l\'idée.';

return [{ json: { message, chatId: data.chatId } }];

// Merge pageId from either direct input or search result
const inputData = $('Normalize Input').first().json;
let pageId;

try {
  pageId = $('Has PageId?').first().json.pageId;
} catch(e) {}

if (!pageId) {
  try {
    pageId = $('Handle Results').first().json.pageId;
  } catch(e) {}
}

return [{ json: { pageId, chatId: inputData.chatId, transcript: inputData.transcript || '' } }];

// Format idea + existing todos for GPT
const allTodos = $input.all();
const idea = $('Fetch Full Idea').first().json;
const mergeData = $('Merge PageId').first().json;

// Format idea
const ideaForGPT = [
  `Titre: ${idea.property_title || idea.name || 'Sans titre'}`,
  `Summary: ${idea.property_summary || 'N/A'}`,
  `Pillar: ${idea.property_pilar || 'N/A'}`,
  `Domain: ${(idea.property_domain || []).join(', ') || 'N/A'}`,
  `Tags: ${(idea.property_tags || []).join(', ') || 'N/A'}`,
  `Status: ${idea.property_status || 'Pas commencé'}`,
  `Difficulty: ${idea.property_difficulty || 'N/A'}`,
  `Impact: ${idea.property_impact || 'N/A'}`,
  `Urgency: ${idea.property_urgency || 'N/A'}`,
  `Clarity: ${idea.property_clarity || 'N/A'}`,
  `ICE: ${idea.property_ice || 'N/A'}`,
  `NextAction: ${idea.property_nextaction || 'N/A'}`,
  `Dependencies: ${idea.property_dependencies || 'Aucune'}`,
  `TimeBucket: ${idea.property_timebucket || 'N/A'}`
].join('\n');

// Format existing todos
const existingTodos = allTodos.map((item, idx) => {
  const t = item.json;
  return {
    order: idx + 1,
    id: t.id,
    title: t.property_title || t.name || 'Sans titre',
    status: t.property_status || 'À faire',
    priority: t.property_priority || 'P2',
    estimatedMinutes: t.property_estimatedminutes || null,
    context: t.property_context || null,
    energyLevel: t.property_energylevel || null,
    validationCriteria: t.property_validationcriteria || null
  };
});

const existingTodosForGPT = existingTodos.length > 0
  ? existingTodos.map(t => 
      `${t.order}. [${t.status}] ${t.title} (${t.priority})` +
      (t.estimatedMinutes ? ` ~${t.estimatedMinutes}min` : ' [pas de durée]') +
      (t.context ? ` @${t.context}` : ' [pas de context]') +
      (t.energyLevel ? ` ⚡${t.energyLevel}` : ' [pas d\'énergie]') +
      (t.validationCriteria ? ` ✓${t.validationCriteria}` : ' [pas de validation]')
    ).join('\n')
  : 'Aucun todo existant.';

return [{
  json: {
    ideaForGPT,
    existingTodosForGPT,
    existingTodos,
    pageId: mergeData.pageId,
    chatId: mergeData.chatId,
    transcript: mergeData.transcript,
    ideaTitle: idea.property_title || idea.name || 'Sans titre'
  }
}];

// Parse GPT response for todos
const gptOutput = $json.output?.[0]?.content?.[0]?.text;
const prevData = $('Format for GPT').first().json;

if (!gptOutput) {
  return [{ json: { error: true, message: 'Pas de réponse GPT', ...prevData } }];
}

try {
  const match = gptOutput.match(/```(?:json)?\s*([\s\S]*?)\s*```/);
  const cleaned = match ? match[1] : gptOutput.trim();
  const parsed = JSON.parse(cleaned);

  return [{ json: { 
    ...parsed,
    existingTodos: prevData.existingTodos,
    pageId: prevData.pageId,
    chatId: prevData.chatId,
    transcript: prevData.transcript,
    ideaTitle: prevData.ideaTitle
  } }];
} catch (e) {
  return [{ json: { 
    error: true, 
    message: 'Erreur parsing: ' + e.message,
    raw: gptOutput,
    ...prevData
  } }];
}

// Match enriched todos with existing todo IDs and split
const data = $('Parse Response').first().json;
const enriched = data.enriched_todos || [];
const existing = data.existingTodos || [];

return enriched.map(e => {
  // Find matching existing todo by title
  const match = existing.find(t => t.title === e.existing_title);
  if (!match) return null;

  return {
    json: {
      todoId: match.id,
      estimatedMinutes: e.estimatedMinutes,
      context: e.context,
      energyLevel: e.energyLevel,
      order: e.order,
      validation: e.validation,
      blocked_by_order: e.blocked_by_order
    }
  };
}).filter(Boolean);

// Split new todos for creation
const data = $('Parse Response').first().json;
const newTodos = data.new_todos || [];
const pageId = data.pageId;

return newTodos.map(todo => ({
  json: {
    ...todo,
    parentIdeaId: pageId,
    createdAt: new Date().toISOString(),
    status: 'À faire',
    source: 'Generated'
  }
}));

